import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  theme, Row, Col, Card, Space, Typography, Select, 
  DatePicker, Button, Table, Statistic, Progress, App, Breadcrumb, Flex 
} from "antd";
import { 
  LineChartOutlined, BarChartOutlined,
  SearchOutlined, DownloadOutlined,
  CheckCircleOutlined, ClockCircleOutlined,
  AlertOutlined, UserOutlined, HomeOutlined
} from "@ant-design/icons";
import ReactECharts from "echarts-for-react";
import ExcelJS from "exceljs";
import dayjs from "dayjs";

const { useToken } = theme;
const { Title, Text } = Typography;
const { RangePicker } = DatePicker;

// --- Realistic Mock Data (Sync with jobs.mock.ts) ---
const mockProjects = [
  { key: "1", prjNm: "자율주행 - 도심 도로 주행 데이터", progress: 89.2, workCnt: 446, goalCnt: 500, personnel: 7, pmNm: "김동현 PM", startDt: "2026-04-01", expireDt: "2026-05-15" },
  { key: "2", prjNm: "CCTV 지능형 안전 통합 관제", progress: 100, workCnt: 1200, goalCnt: 1200, personnel: 12, pmNm: "이지수 PM", startDt: "2026-03-20", expireDt: "2026-04-30" },
  { key: "3", prjNm: "의료 영상 판독용 AI 데이터셋", progress: 65.0, workCnt: 8500, goalCnt: 12000, personnel: 25, pmNm: "박미나 PM", startDt: "2026-04-05", expireDt: "2026-06-30" },
  { key: "4", prjNm: "스마트 팩토리 안전화 인식", progress: 88, workCnt: 88, goalCnt: 100, personnel: 5, pmNm: "강동수 PM", startDt: "2026-04-10", expireDt: "2026-05-25" },
];

export default function StatOverallPage() {
  const { token } = useToken();
  const { t } = useTranslation(["stats", "common", "project", "labeling"]);
  const { message } = App.useApp();

  const [selectedPrj, setSelectedPrj] = useState<string>("all");
  const [dateRange, setDateRange] = useState<any>(null);
  const [displayData, setDisplayData] = useState(mockProjects);
  const [loading, setLoading] = useState(false);

  const totalWork = displayData.reduce((acc, cur) => acc + cur.workCnt, 0);

  const handleSearch = () => {
    setLoading(true);
    setTimeout(() => {
      const filtered = selectedPrj === "all" ? mockProjects : mockProjects.filter(p => p.key === selectedPrj);
      setDisplayData(filtered);
      setLoading(false);
      message.success(t("confirm", { ns: "common" }));
    }, 500);
  };

  const handleExport = async () => {
    const workbook = new ExcelJS.Workbook();
    const worksheet = workbook.addWorksheet("Statistics");
    worksheet.columns = [
      { header: t("modal.prjNm", { ns: "project" }), key: "prjNm", width: 30 },
      { header: t("modal.goal", { ns: "project" }), key: "goalCnt", width: 15 },
      { header: t("columns.workCount", { ns: "project" }), key: "workCnt", width: 15 },
      { header: t("progress", { ns: "project" }), key: "progress", width: 15 },
    ];
    displayData.forEach(item => worksheet.addRow(item));
    const buffer = await workbook.xlsx.writeBuffer();
    const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
    const link = document.createElement("a");
    link.href = window.URL.createObjectURL(blob);
    link.download = `StatOverall_${dayjs().format("YYYYMMDD")}.xlsx`;
    link.click();
    message.success(t("msg.exportDone", { ns: "project" }));
  };

  return (
    <div style={{ padding: "0 24px 24px 24px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-end", marginBottom: 20 }}>
        <div>
          <Title level={4} style={{ margin: 0 }}>{t("tabs.overall")}</Title>
        </div>
        <Flex vertical align="flex-end" gap={8}>
          <Breadcrumb 
            items={[
              { title: <Space><HomeOutlined /> {t("listPage.home", { ns: "labeling" })}</Space> },
              { title: t("title") },
              { title: t("tabs.overall") }
            ]} 
          />
          <Space>
            <RangePicker size="small" value={dateRange} onChange={setDateRange} />
            <Select 
              size="small" value={selectedPrj} style={{ width: 220 }} onChange={setSelectedPrj}
              placeholder={t("modal.prjNm", { ns: "project" })}
            >
              <Select.Option value="all">{t("total", { ns: "common" })} ({t("total", { ns: "common" })})</Select.Option>
              {mockProjects.map(p => <Select.Option key={p.key} value={p.key}>{p.prjNm}</Select.Option>)}
            </Select>
            <Button type="primary" size="small" icon={<SearchOutlined />} onClick={handleSearch} loading={loading}>{t("search", { ns: "common" })}</Button>
            <Button size="small" icon={<DownloadOutlined />} onClick={handleExport}>{t("export", { ns: "project" })}</Button>
          </Space>
        </Flex>
      </div>

      <Row gutter={16} style={{ marginBottom: 16 }}>
        <Col span={6}>
          <Card variant="borderless" style={{ height: "100%", background: token.colorFillTertiary }}>
            <Statistic title={t("overall.totalProcessed")} value={totalWork} suffix={t("unitCases", { ns: "common" })} prefix={<CheckCircleOutlined style={{ color: token.colorSuccess }} />} />
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ height: "100%", background: token.colorFillTertiary }}>
            <Statistic title={t("overall.goalCompletionRate")} value={85.4} suffix="%" prefix={<AlertOutlined style={{ color: token.colorWarning }} />} />
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ height: "100%", background: token.colorFillTertiary }}>
            <Statistic title={t("overall.avgDaily")} value={342} suffix={t("unitCases", { ns: "common" })} prefix={<UserOutlined style={{ color: token.colorInfo }} />} />
          </Card>
        </Col>
        <Col span={6}>
          <Card variant="borderless" style={{ height: "100%", background: token.colorFillTertiary }}>
            <Statistic title={t("overall.expectedFinish")} value="2026-05" prefix={<ClockCircleOutlined style={{ color: token.colorWarning }} />} />
          </Card>
        </Col>
      </Row>

      <Row gutter={16}>
        <Col span={16}>
          <Card title={<Space><LineChartOutlined /> {t("overall.dailyTrend")}</Space>} variant="borderless" style={{ background: token.colorBgContainer }}>
            <ReactECharts 
              option={{
                xAxis: { type: 'category', data: [t('overall.days.mon'), t('overall.days.tue'), t('overall.days.wed'), t('overall.days.thu'), t('overall.days.fri'), t('overall.days.sat'), t('overall.days.sun')] },
                yAxis: { type: 'value' },
                series: [{ data: [150, 230, 224, 218, 135, 147, 260], type: 'line', smooth: true }]
              }}
              style={{ height: 350 }} 
            />
          </Card>
        </Col>
        <Col span={8}>
          <Card title={<Space><BarChartOutlined /> {t("defect.analysis")}</Space>} variant="borderless">
            <ReactECharts 
              option={{
                tooltip: { trigger: 'item' },
                series: [{ type: 'pie', radius: '50%', data: [{ value: 10, name: t('charts.normal') }, { value: 2, name: t('charts.error') }] }]
              }}
              style={{ height: 350 }} 
            />
          </Card>
        </Col>
      </Row>

      <Card title={t("overall.summary")} variant="borderless" style={{ marginTop: 16 }}>
        <Table 
          size="small" dataSource={displayData} pagination={false}
          columns={[
            { title: t("modal.prjNm", { ns: "project" }), dataIndex: "prjNm" },
            { title: t("modal.goal", { ns: "project" }), dataIndex: "goalCnt", align: "right", render: (v) => v.toLocaleString() },
            { title: t("columns.workCount", { ns: "project" }), dataIndex: "workCnt", align: "right", render: (v) => v.toLocaleString() },
            { title: t("progress", { ns: "project" }), dataIndex: "progress", width: 250, render: (v) => <Progress percent={v} size="small" /> },
          ]}
        />
      </Card>
    </div>
  );
}
